SELECT ?person ?personLabel (COUNT(?person) AS ?count)
WHERE {
  ?event wdt:P1552 wd:Q61914284 .
  ?event wdt:P1022 ?person .
  OPTIONAL { ?person rdfs:label ?personLabel . FILTER (LANG(?personLabel) = "en") }
}
GROUP BY ?person ?personLabel
ORDER BY DESC(?count)
LIMIT 1

